// Load script setelah DOM berhasil dimuat
$(function () {
    let $formEditReminder = $("#formEditReminder");
    let formCekEditReminder = FormHelper.cekFormData($formEditReminder);

    TableHelper.init("#tableReminderSetting", {
        ajax: window.routes.dataTable, // Mengambil endpoint url data tabel dari global window variabel
        order: [[0, "asc"]], // Urut berdasarkan kolom yang ditentukan
        filters: [1], // Filter untuk Status & Jenis saja
        urlOpsiFilter: window.routes.opsiFilter, // Mengambil endpoint url opsi filter dari global window variabel
        keyMap: {
            // Wajib untuk kolom yang berbeda dengan header kolom di tabel
            pengguna: "name",
        },
        columns: [
            {
                data: "id",
                title: "ID",
                className: "dt-head-center dt-body-center",
            },
            {
                data: "name",
                title: "Pengguna",
                className: "dt-head-center dt-body-center",
            },
            {
                data: "payload",
                title: "Hari Reminder",
                className: "dt-head-center dt-body-center",
            },
            {
                data: "admin_buat",
                title: "Pembuat",
                orderable: false,
                className: "dt-head-center dt-body-center",
            },
            {
                data: "admin_ubah",
                title: "Pengubah",
                orderable: false,
                className: "dt-head-center dt-body-center",
            },
            {
                data: "created_at",
                title: "Dibuat",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "updated_at",
                title: "Diubah",
                className: "dt-head-center dt-body-center",
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "aksi",
                title: "Aksi",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: (data, type) => (type === "display" ? data : ""),
            },
        ],
    });

    // Ambil reminder berdasarkan id untuk proses edit data
    $(document).on(
        "click",
        '#tableReminderSetting button[data-target="#modalEditReminder"]',
        function () {
            let id = $(this).data("id");
            let url = window.routes.getReminder.replace(":id", id); // Mengambil route endpoint yang telah didefinisikan pada global window variabel
            let $form = $formEditReminder;

            $.get(url)
                .done(function (res) {
                    let reminder = res.reminder;

                    $form[0].reset();
                    $form.validate().resetForm();
                    $form
                        .find(".is-valid, .is-invalid")
                        .removeClass("is-valid is-invalid");

                    // Mendefinisikan endpoint route dari global window untuk edit reminder
                    $form.attr(
                        "action",
                        window.routes.updateReminder.replace(":id", id)
                    );

                    $("#edit_payload").val(reminder.payload);

                    // insialisasi ulang data untuk deteksi perubahan Form Edit
                    formCekEditReminder = FormHelper.cekFormData($form);
                })
                .fail(function (xhr) {
                    let message =
                        (xhr.responseJSON && xhr.responseJSON.message) ||
                        "Terjadi kesalahan saat mengambil data reminder.";

                    Swal.fire({
                        icon: "error",
                        title: "Gagal memuat data!",
                        text: message,
                    });
                });
        }
    );

    // Edit Reminder
    $formEditReminder.validate(
        $.extend(FormHelper.validasiForm(), {
            rules: {
                payload: {
                    required: true,
                    customReminderFormatPayload: true,
                },
            },
            submitHandler: function (form) {
                if (!formCekEditReminder.isChanged()) return false;
                return FormHelper.submitForm(
                    form,
                    $(form).attr("action"),
                    $(form).find("button[type=submit]"),
                    $(form).find("#btn-loading"),
                    {
                        formCek: formCekEditReminder,
                        $modalDiv: $("#modalEditReminder"),
                        $tabelData: $("#tableReminderSetting"),
                        $btnClose: $("#modalEditReminder").find(
                            '[data-dismiss="modal"]'
                        ),
                        $options: {
                            // loadStats: loadStats,
                        },
                    }
                );
            },
        })
    );
});